const r="http://localhost:3001";chrome.runtime.onMessage.addListener((e,n,o)=>{if(e.type==="ANALYZE_PROBLEM"){const a=e.payload;return fetch(`${r}/analyze`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(a)}).then(t=>{if(!t.ok)throw new Error(`Server error: ${t.status}`);return t.json()}).then(t=>{o({type:"ANALYSIS_RESULT",payload:t})}).catch(t=>{o({type:"ANALYSIS_ERROR",payload:t.message})}),!0}});
